import (
	"fmt"
	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Optimization: Create a single VM instance to be reused for all items.
	// Creating a new VM for every item is expensive and unnecessary.
	vm := otto.New()

	// Optimization: Compile the script once before the loop.
	// This avoids re-parsing the JavaScript source code for every item in the slice.
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	var result []map[string]interface{}

	for _, item := range items {
		// Inject the current item as a global variable named 'item'.
		// Since we are reusing the VM, this overwrites the 'item' variable from the previous iteration.
		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Run the pre-compiled script.
		value, err := vm.Run(script)
		if err != nil {
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness.
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

func main() {
	// Example usage based on the requirements
	items := []map[string]interface{}{
		{"id": 1, "active": true},
		{"id": 2, "active": false},
		{"id": 3, "active": true},
	}

	script := `item.active == true`

	filtered, err := FilterItems(script, items)
	if err != nil {
		fmt.Printf("Error filtering items: %v\n", err)
		return
	}

	fmt.Printf("Filtered Items: %+v\n", filtered)
}

