	vmCompile := otto.New()
	script, err := vmCompile.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("script compilation error: %w", err)
	}

	var result []map[string]interface{}

	// 2. Define a timeout for script execution to prevent DoS.
	// This ensures a single item's script doesn't hang the entire application.
	const executionTimeout = 10 * time.Millisecond

	for _, item := range items {
		// 3. Create a fresh VM for each item to ensure isolation.
		// This prevents the script from leaking global state (variables, functions) between items.
		vm := otto.New()

		// Inject the current item as a global variable named 'item'
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to set item variable: %w", err)
		}

		// 4. Run the script with a timeout.
		ctx, cancel := context.WithTimeout(context.Background(), executionTimeout)
		defer cancel()

		done := make(chan struct{}, 1)
		var value otto.Value
		var runErr error

		go func() {
			defer close(done)
			// Run the pre-compiled script on the new VM
			value, runErr = vm.Run(script)
