		// Execute the script in a separate goroutine to enforce a timeout.
		// This prevents malicious scripts (e.g., `while(true){}`) from hanging the application indefinitely.
		type scriptResult struct {
			value otto.Value
			err   error
		}

		resultChan := make(chan scriptResult, 1)

		go func() {
			val, err := vm.Run(script)
			resultChan <- scriptResult{value: val, err: err}
			close(resultChan)
		}()

		select {
		case res := <-resultChan:
			if res.err != nil {
				return nil, res.err
			}

			// Convert result to boolean using JavaScript truthiness
			boolResult, err := res.value.ToBoolean()
			if err != nil {
				return nil, err
			}

			if boolResult {
				result = append(result, item)
			}
		case <-time.After(500 * time.Millisecond):
