// deepCopy creates a deep copy of a map[string]interface{} to prevent
// the JavaScript script from modifying the original data items.
// This addresses the security issue of data integrity/tampering.
func deepCopy(original map[string]interface{}) map[string]interface{} {
	copy := make(map[string]interface{})
	for key, value := range original {
		// Recursively copy nested maps
		if nestedMap, ok := value.(map[string]interface{}); ok {
			copy[key] = deepCopy(nestedMap)
		} else {
			copy[key] = value
		}
	}
